 93         FunctionType::get(Type::getVoidTy(RegularLTO.Ctx), false),
 94         GlobalValue::ExternalLinkage, "thinlto_remark_dummy",
 95         DummyModule.get());
 96   }
 97 
 98   return Error::success();
 99 }
